& \mathbf{r}_{s} \cdot \mathbf{n}=0  \tag{1}\\
& \mathbf{r}_{t} \cdot \mathbf{n}=0 \tag{2}
\end{align*}
\]

\[
\begin{equation*}
I(\mathbf{w}, \mathbf{w})=\mathbf{w} \cdot \mathbf{w} \tag{3}
\end{equation*}
\]

\[
\mathbf{G}=\left[\begin{array}{ll}
\mathbf{r}_{s} \cdot \mathbf{r}_{s} & \mathbf{r}_{s} \cdot \mathbf{r}_{t}  \tag{4}\\
\mathbf{r}_{t} \cdot \mathbf{r}_{s} & \mathbf{r}_{t} \cdot \mathbf{r}_{t}
\end{array}\right]
\]

\[
\begin{equation*}
I I(\mathbf{w}, \mathbf{w})=-\mathbf{w} \cdot \mathbf{L}(\mathbf{w}) \tag{5}
\end{equation*}
\]

\[
\begin{align*}
& \mathbf{L}\left(\mathbf{r}_{s}\right)=\mathbf{n}_{s}  \tag{6}\\
& \mathbf{L}\left(\mathbf{r}_{t}\right)=\mathbf{n}_{t} \tag{7}
\end{align*}
\]

\[
\mathbf{D}=\left[\begin{array}{ll}
\mathbf{r}_{s s} \cdot \mathbf{n} & \mathbf{r}_{s t} \cdot \mathbf{n}  \tag{8}\\
\mathbf{r}_{t s} \cdot \mathbf{n} & \mathbf{r}_{t t} \cdot \mathbf{n}
\end{array}\right]
\]

\[
\begin{equation*}
\kappa^{n}=\frac{I I(\mathbf{w}, \mathbf{w})}{I(\mathbf{w}, \mathbf{w})} \tag{9}
\end{equation*}
\]

\[
\begin{equation*}
\mathbf{r}(s, t)=\mathbf{v}(t)+\lambda(s, t) \mathbf{Q}(s, t) \tag{10}
\end{equation*}
\]

\[
\begin{equation*}
\mathbf{Q} \cdot \mathbf{n}=0 \tag{11}
\end{equation*}
\]

\[
\begin{equation*}
\mathbf{Q}=R(t) \tilde{\mathbf{Q}} \tag{12}
\end{equation*}
\]

\[
\begin{equation*}
\mathbf{Q}(s, 0)=\tilde{\mathbf{Q}}(s, 0) \tag{13}
\end{equation*}
\]

\[
\begin{gather*}
\mathbf{U}=\mathbf{v}_{t}  \tag{14}\\
\mathbf{\Omega} \wedge \tilde{\mathbf{Q}}=R_{t} \tilde{\mathbf{Q}} \tag{15}
\end{gather*}
\]

\[
\begin{equation*}
\mathbf{Q}_{t}=\tilde{\mathbf{Q}}_{t}+\mathbf{\Omega} \wedge \tilde{\mathbf{Q}} \tag{16}
\end{equation*}
\]

\[
\begin{equation*}
\mathbf{r}_{s}=\lambda_{s} \mathbf{Q}+\lambda \mathbf{Q}_{s} \tag{17}
\end{equation*}
\]

\[
\begin{aligned}
& \mathbf{r}_{s} \cdot \mathbf{n}=0 \\
& \mathbf{Q} \cdot \mathbf{n}=0
\end{aligned}
\]

\[
\begin{equation*}
\mathbf{Q}_{s} \cdot \mathbf{n}=0 \tag{18}
\end{equation*}
\]

\[
\begin{equation*}
\mathbf{n}=\frac{\mathbf{Q} \wedge \mathbf{Q}_{s}}{\left|\mathbf{Q} \wedge \mathbf{Q}_{s}\right|} \tag{19}
\end{equation*}
\]

\[
\begin{align*}
I\left(\mathbf{Q}, \mathbf{r}_{s}\right) & =-\mathbf{Q} \cdot \mathbf{L}\left(\mathbf{r}_{s}\right) \\
& =-\mathbf{Q} \cdot \mathbf{n}_{s} \tag{20}
\end{align*}
\]

\[
\begin{equation*}
\mathbf{Q} \cdot \mathbf{n}_{s}=0 \tag{21}
\end{equation*}
\]

\[
\mathbf{n}\left(s, t_{0}\right)=\frac{\mathbf{Q} \wedge \mathbf{Q}_{s}}{\left|\mathbf{Q} \wedge \mathbf{Q}_{s}\right|}
\]

\[
\begin{equation*}
\kappa^{p}=\frac{\mathbf{Q}_{s s} \cdot \mathbf{n}}{\left|\mathbf{Q}_{s}\right|^{2}} \tag{22}
\end{equation*}
\]

\[
\begin{equation*}
\kappa^{p}=\frac{\lambda \kappa^{s}}{\sin ^{2} \theta} \tag{23}
\end{equation*}
\]

\[
\begin{equation*}
K=\frac{\kappa^{p} \kappa^{t}}{\lambda} \tag{24}
\end{equation*}
\]

\[
\begin{equation*}
\mathbf{r}_{t} \wedge \mathbf{Q}=0 \tag{25}
\end{equation*}
\]

\[
\begin{equation*}
\mathbf{Q}_{t}=\frac{(\mathbf{U} \wedge \mathbf{Q}) \wedge \mathbf{Q}}{\lambda} \tag{26}
\end{equation*}
\]

\[
\begin{equation*}
\tilde{\mathbf{Q}}_{t}=\frac{(\mathbf{U} \wedge \tilde{\mathbf{Q}}) \wedge \tilde{\mathbf{Q}}}{\lambda}-\mathbf{\Omega} \wedge \tilde{\mathbf{Q}} \tag{27}
\end{equation*}
\]

\[
\begin{equation*}
\mathbf{r}_{t}=\left(\frac{\mathbf{Q}_{t} \cdot \mathbf{n}}{\kappa^{t}}\right) \mathbf{Q} \tag{28}
\end{equation*}
\]

\[
\begin{equation*}
\kappa^{t}=\frac{\mathbf{r}_{t t} \cdot \mathbf{n}}{\mathbf{r}_{t} \cdot \mathbf{r}_{t}} \tag{29}
\end{equation*}
\]

\[
\begin{equation*}
\mathbf{r}_{t}=\left(\lambda_{t}+\mathbf{Q} \cdot \mathbf{U}\right) \mathbf{Q} \tag{30}
\end{equation*}
\]

\[
\begin{equation*}
\boldsymbol{\kappa}^{t}=\frac{\mathbf{Q}_{t} \cdot \mathbf{n}}{\left(\lambda_{t}+\mathbf{Q} \cdot \mathbf{U}\right)} \tag{31}
\end{equation*}
\]

\[
\begin{equation*}
\lambda=-\frac{\mathbf{U} \cdot \mathbf{n}}{\mathbf{Q}_{t} \cdot \mathbf{n}} \tag{32}
\end{equation*}
\]

\[
\begin{equation*}
\lambda=-\frac{\mathbf{U} \cdot \mathbf{n}}{\tilde{\mathbf{Q}}_{t} \cdot \mathbf{n}+(\mathbf{\Omega} \wedge \tilde{\mathbf{Q}}) \cdot \mathbf{n}} \tag{33}
\end{equation*}
\]

\[
\begin{align*}
\mathbf{G} & =\left[\begin{array}{cc}
1 & \cos \theta \\
\cos \theta & 1
\end{array}\right]  \tag{34}\\
\mathbf{D} & =\left[\begin{array}{cc}
\kappa^{s} & 0 \\
0 & \kappa^{t}
\end{array}\right] \tag{35}
\end{align*}
\]

\[
\begin{equation*}
\tan \theta=\frac{\lambda\left|\mathbf{Q}_{s}\right|}{\lambda_{s}} \tag{36}
\end{equation*}
\]

\[
\begin{equation*}
\kappa^{s}=\frac{\kappa^{p} \sin ^{2} \theta}{\lambda} \tag{37}
\end{equation*}
\]

\[
\begin{equation*}
\boldsymbol{\kappa}^{t}=-\frac{\mathbf{U} \cdot \mathbf{n}}{\lambda\left(\lambda_{t}+\tilde{\mathbf{Q}} \cdot \mathbf{U}\right)} \tag{38}
\end{equation*}
\]

\[
\begin{align*}
\tilde{\mathbf{Q}}_{t t} \cdot \mathbf{n}= & -\frac{(\mathbf{U} \cdot \mathbf{n})^{2}}{(\lambda)^{3}}\left[\frac{1}{\kappa^{t}}\right]-2 \frac{(\tilde{\mathbf{Q}} \cdot \mathbf{U})(\mathbf{U} \cdot \mathbf{n})}{(\lambda)^{2}} \\
& -\frac{\mathbf{U}_{t} \cdot \mathbf{n}}{\lambda}-\left(\mathbf{Q}_{t} \wedge \tilde{\mathbf{Q}}\right) \cdot \mathbf{n} \\
& -\frac{2(\tilde{\mathbf{Q}} \cdot \mathbf{U})(\mathbf{\Omega} \wedge \tilde{\mathbf{Q}}) \cdot \mathbf{n}}{\lambda} \\
& +\frac{(\mathbf{\Omega} \wedge U) \cdot \mathbf{n}}{\lambda}+(\mathbf{\Omega} \cdot \tilde{\mathbf{Q}})(\mathbf{\Omega} \cdot \mathbf{n}) \tag{39}
\end{align*}
\]

\[
K=\frac{\kappa^{p} \kappa^{t}}{\lambda}
\]

\[
\begin{align*}
H & =\frac{1}{2}\left[\frac{\kappa^{p}}{\lambda}+\kappa^{t} \operatorname{cosec}^{2} \theta\right]  \tag{40}\\
\kappa_{1,2} & =H \pm \sqrt{H^{2}-K} \tag{41}
\end{align*}
\]

\[
\begin{equation*}
\tilde{\mathbf{Q}}_{t}^{(i)}=\left[\left(\mathbf{U} \wedge \tilde{\mathbf{Q}}^{(i)}\right) \wedge \tilde{\mathbf{Q}}^{(i)}\right] \quad \frac{1}{\lambda^{(i)}} \quad-\mathbf{\Omega} \wedge \tilde{\mathbf{Q}}^{(i)} \tag{42}
\end{equation*}
\]

\[
\begin{equation*}
\delta(t)=\tilde{\mathbf{Q}}^{(2)}-\tilde{\mathbf{Q}}^{(1)} \tag{43}
\end{equation*}
\]

\[
\tilde{\mathbf{Q}}^{(1)}(0)=\tilde{\mathbf{Q}}^{(2)}(0)=\tilde{\mathbf{Q}}
\]

\[
\begin{equation*}
\delta_{t}=[(\mathbf{U} \wedge \tilde{\mathbf{Q}}) \wedge \tilde{\mathbf{Q}}]\left[\frac{1}{\lambda^{(2)}}-\frac{1}{\lambda^{(1)}}\right] \tag{44}
\end{equation*}
\]

\[
\begin{align*}
\tilde{\mathbf{Q}}_{t t}^{(i)} \cdot \mathbf{n}^{(i)}= & -\frac{\left(\mathbf{U} \cdot \mathbf{n}^{(i)}\right)^{2}}{\left(\lambda^{(i)}\right)^{3}}\left[\frac{1}{\kappa^{i t}}\right] \\
& -2 \frac{\left(\mathbf{U} \cdot \tilde{\mathbf{Q}}^{(i)}\right)\left(\mathbf{U} \cdot \mathbf{n}^{(i)}\right)}{\left(\lambda^{(i)}\right)^{2}} \\
& -\frac{\mathbf{U}_{t} \cdot \mathbf{n}^{(i)}}{\lambda^{(i)}}-\left(\boldsymbol{\Omega}_{t} \wedge \tilde{\mathbf{Q}}^{(i)}\right) \cdot \mathbf{n}^{(i)} \\
& -\frac{2\left(\mathbf{U} \cdot \tilde{\mathbf{Q}}^{(i)}\left(\boldsymbol{\Omega} \wedge \tilde{\mathbf{Q}}^{(i)}\right) \cdot \mathbf{n}^{(i)}\right.}{\lambda^{(i)}} \\
& +\frac{(\boldsymbol{\Omega} \wedge \mathbf{U}) \cdot \mathbf{n}^{(i)}}{\lambda^{(i)}} \\
& +\left(\boldsymbol{\Omega} \cdot \tilde{\mathbf{Q}}^{(i)}\right)\left(\boldsymbol{\Omega} \cdot \mathbf{n}^{(i)}\right) \tag{45}
\end{align*}
\]

\[
\begin{equation*}
\Delta R=\frac{1}{\kappa^{t 2}}-\frac{1}{\kappa^{t 1}} \tag{46}
\end{equation*}
\]

\[
\begin{equation*}
\delta_{t t} \cdot \mathbf{n}=-\frac{(\mathbf{U} \cdot \mathbf{n})^{2}}{\lambda^{3}} \Delta R \tag{47}
\end{equation*}
\]

\[
\begin{equation*}
\Delta R=\Delta \hat{R}+R^{\mathrm{error}} \tag{48}
\end{equation*}
\]

\[
\begin{equation*}
\Delta \hat{R}=-\frac{\lambda^{3}}{(\mathbf{U} \cdot \mathbf{n})^{2}} \delta_{t t} \cdot \mathbf{n} \tag{49}
\end{equation*}
\]

\[
\begin{equation*}
\left|R^{\text {error }}\right| \approx 9 \lambda|\delta|+\lambda^{3}|\delta| \frac{\left|\Omega_{t}\right|}{(\mathbf{U} \cdot \mathbf{n})^{2}}+\lambda|\Delta \lambda| \frac{\mathbf{U}_{t} \cdot \mathbf{n}}{(\mathbf{U} \cdot \mathbf{n})^{2}} \tag{50}
\end{equation*}
\]

\[
\begin{equation*}
|\delta| \ll \frac{\Delta R}{9 \lambda} \tag{51}
\end{equation*}
\]

\[
\begin{equation*}
E_{\text {internal }}=\frac{\alpha\left|\mathbf{x}_{s}\right|^{2}+\beta\left|\mathbf{x}_{s s}\right|^{2}}{2} \tag{52}
\end{equation*}
\]

\[
\begin{equation*}
E_{\text {external }}=-|\nabla G(\sigma) * I(\mathbf{x}(s))|^{2} \tag{53}
\end{equation*}
\]

\[
\begin{equation*}
\mathbf{x}(s)=\sum_{i} f_{i}(s) \mathbf{q}_{i} \tag{54}
\end{equation*}
\]

\[
\begin{equation*}
\mathbf{F}\left(s_{j}\right)=\nabla\left|\nabla G(\sigma) * I\left(\mathbf{x}\left(s_{j}\right)\right)\right| \tag{55}
\end{equation*}
\]

\[
\begin{equation*}
\sum_{j}\left[\mathbf{y}\left(s_{j}\right)-\sum_{i} f_{i}\left(s_{j}\right) \mathbf{q}_{i}\right]^{2} \tag{56}
\end{equation*}
\]

\[
\begin{equation*}
\sum_{i} \mathbf{q}_{i} \sum_{j} f_{i} f_{k}=\sum_{j} f_{k} \mathbf{y}\left(s_{j}\right) \tag{57}
\end{equation*}
\]

\[
\begin{align*}
X_{t}(0) & =-\frac{f U}{\lambda}  \tag{58}\\
X_{t t}(0) & =-\frac{f U^{2} R}{\lambda^{3}} \tag{59}
\end{align*}
\]

\[
\begin{equation*}
\kappa^{t}=\frac{1}{R} \cos \phi \tag{60}
\end{equation*}
\]

