K=\frac{\kappa^{s} \kappa^{t}}{\sin ^{2} \theta}
\]

\[
\begin{equation*}
\left.\frac{\partial \tilde{\mathbf{Q}}}{\partial t}\right|_{\bar{s}}=\beta \mathbf{n} \tag{62}
\end{equation*}
\]

\[
\begin{align*}
\tilde{\mathbf{Q}} & =\tilde{\mathbf{Q}}^{*}  \tag{68}\\
\tilde{\mathbf{Q}}_{t} & =\tilde{\mathbf{Q}}_{t}^{*} \tag{69}
\end{align*}
\]

\[
\begin{equation*}
\left.\frac{\partial \bar{s}}{\partial t}\right|_{s}=\frac{\left.\tilde{\mathbf{Q}}_{t} \cdot{ }^{\partial \tilde{\mathbf{Q}}}\right|_{\partial \bar{s}}}{\left.\left|\frac{\partial \tilde{\mathbf{Q}}}{\partial \bar{s}}\right|_{t}\right|^{2}} \tag{70}
\end{equation*}
\]

\[
\begin{aligned}
\mathbf{Q}^{(2)} & =\mathbf{Q} \\
\mathbf{Q}^{(1)} & =\mathbf{Q}+\Delta \mathbf{Q} \\
\lambda^{(2)} & =\lambda \\
\lambda^{(1)} & =\lambda+\Delta \lambda \\
\mathbf{Q}^{(2)} \cdot \mathbf{n} & =0 \\
\mathbf{Q}^{(1)} \cdot \mathbf{n} & =\Delta \mathbf{Q} \cdot \mathbf{n}
\end{aligned}
\]

\[
\begin{equation*}
\Delta \hat{R}=\frac{(\mathbf{U} \cdot \mathbf{n})^{2}}{\lambda^{3}} \frac{1}{\delta_{t t} \cdot \mathbf{n}} \tag{71}
\end{equation*}
\]

\[
\begin{equation*}
\Delta R=\Delta \hat{R}+R^{\text {error }} \tag{72}
\end{equation*}
\]

\[
\begin{equation*}
R^{\text {error }}=R^{\Delta \lambda}+R^{\Delta \mathbf{Q}}+R^{\mathbf{n}} \tag{73}
\end{equation*}
\]

\[
\begin{aligned}
R^{\Delta \lambda}= & \Delta \lambda\left[\frac{3}{\lambda \kappa^{t 2}}+\frac{4 \mathbf{U} \cdot \mathbf{Q}}{\mathbf{U} \cdot \mathbf{n}}+\frac{\lambda \mathbf{U}_{t} \cdot \mathbf{n}}{(\mathbf{U} \cdot \mathbf{n})^{2}}\right. \\
& \left.+\frac{2 \lambda(\mathbf{U} \cdot \mathbf{Q})(\mathbf{\Omega} \wedge \mathbf{Q}) \cdot \mathbf{n}}{(\mathbf{U} \cdot \mathbf{n})^{2}}+\frac{\lambda(\mathbf{U} \wedge \mathbf{\Omega}) \cdot \mathbf{n}}{(\mathbf{U} \cdot \mathbf{n})^{2}}\right]
\end{aligned}
\]
